import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getSmartDonorMatch = async (bloodRequest: any) => {
  const prompt = `Analyze this blood request and suggest a matching strategy: 
  Patient: ${bloodRequest.patientName}, 
  Blood Group Needed: ${bloodRequest.bloodGroup}, 
  Urgency: ${bloodRequest.urgency},
  Hospital: ${bloodRequest.hospital}.
  Provide 3 specific tips for the family to secure this donor quickly in Bangladesh context.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 }
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "AI matching engine currently unavailable. Please proceed with standard protocols.";
  }
};

export const getHealthTipsForDonors = async () => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: "Provide 5 concise health tips for a first-time blood donor in Bangladesh, focusing on local nutrition and weather conditions.",
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              tip: { type: Type.STRING },
              description: { type: Type.STRING }
            },
            required: ["tip", "description"]
          }
        }
      }
    });
    return JSON.parse(response.text || "[]");
  } catch (error) {
    return [];
  }
};

import React, { useState, useEffect } from 'react';
import { View } from './types';
import LandingView from './views/LandingView';
import RegistrationView from './views/RegistrationView';
import RequestView from './views/RequestView';
import LoginView from './views/LoginView';
import DashboardView from './views/DashboardView';
import Navbar from './components/Navbar';
import Footer from './components/Footer';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('home');
  const [isAdmin, setIsAdmin] = useState(false);

  // Simple state-based routing
  const renderView = () => {
    switch (currentView) {
      case 'home': return <LandingView onViewChange={setCurrentView} />;
      case 'register': return <RegistrationView onComplete={() => setCurrentView('home')} />;
      case 'request': return <RequestView onComplete={() => setCurrentView('home')} />;
      case 'login': return <LoginView onLogin={(user) => { setIsAdmin(true); setCurrentView('dashboard'); }} />;
      case 'dashboard': return isAdmin ? <DashboardView onLogout={() => { setIsAdmin(false); setCurrentView('home'); }} /> : <LoginView onLogin={() => { setIsAdmin(true); setCurrentView('dashboard'); }} />;
      default: return <LandingView onViewChange={setCurrentView} />;
    }
  };

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [currentView]);

  if (currentView === 'dashboard') {
    return <DashboardView onLogout={() => { setIsAdmin(false); setCurrentView('home'); }} />;
  }

  return (
    <div className="flex flex-col min-h-screen">
      <Navbar currentView={currentView} onViewChange={setCurrentView} />
      <main className="flex-grow">
        {renderView()}
      </main>
      <Footer onViewChange={setCurrentView} />
    </div>
  );
};

export default App;

